#!/usr/bin/env bash
# account-planning-land-and-expand.sh — Account planning / land-and-expand（客户计划 / 落地后扩张） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Account planning / land-and-expand（客户计划 / 落地后扩张）"

usage() {
  cat <<EOF
account-planning-land-and-expand.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./account-planning-land-and-expand.sh             # interactive
  ./account-planning-land-and-expand.sh --dry-run
  ./account-planning-land-and-expand.sh --json
  ./account-planning-land-and-expand.sh --explain
  ./account-planning-land-and-expand.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Account planning / land-and-expand（客户计划 / 落地后扩张）" 工作流。

一句话: After the first win, deliberately *land small then expand* — build an account plan (stakeholders, whitespace, expansion path), prove value in QBRs, and grow seats/products (the NRR engine). The post-sale revenue motion that's cheaper than new logos. (evidence: [T03-S026, T03-S027])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Land a deliberate beachhead** — win a focused first deal you can deliver and prove value on (not the biggest-possible first contract). (evidence: [T03-S026])"
  "**Build the account plan** — map stakeholders (incl. ones outside the first deal), document the relationship, and define the expansion strategy. (evidence: [T03-S027])"
  "**Run whitespace analysis** — identify un-penetrated products/teams/use-cases inside the account proactively (not just at renewal). (evidence: [T03-S026])"
  "**Validate value in QBRs** — use the Quarterly Business Review to prove delivered outcomes, then open expansion conversations from a position of proven value. (evidence: [T03-S027, T03-S026])"
  "**Sequence the expansion** — convert whitespace + proven value into a land-and-expand motion (more seats, new products/teams) over the account lifecycle. (evidence: [T03-S026])"
)
declare -a FAILURE_MODES=(
  "**Pitching expansion before proving value**: a cold upsell at renewal the buyer resists — and it can sour the renewal itself. Avoid: validate delivered outcomes in a QBR first, then expand from proven value. (evidence: [T03-S027])"
  "**Over-sized first deal that under-delivers → logo churn**: you lose the account before you can expand. Avoid: land a deliberate, deliverable beachhead. (evidence: [T03-S026])"
  "**Single-threaded account → champion leaves, account at risk**: relying on the original buyer. Avoid: multithread across the account early; build a whitespace + stakeholder map. (evidence: [T03-S028])"
  "**No whitespace analysis → flat NRR + competitor lands in the gap**: expansion revenue left on the table. Avoid: proactively map un-penetrated products/teams/use-cases. (evidence: [T03-S026])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "account-planning-land-and-expand-walkthrough"
fi
